"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[7872],{84794(r,n,t){t.r(n),t.d(n,{assets:()=>c,contentTitle:()=>a,default:()=>u,frontMatter:()=>d,metadata:()=>e,toc:()=>i});const e=JSON.parse('{"id":"cpp11/range-based-for","title":"\u8303\u56f4for\u5faa\u73af (Range-based for loop)","description":"C++11 \u8303\u56f4for\u5faa\u73af (Range-based for loop) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp11/02-range-based-for.md","sourceDirName":"cpp11","slug":"/cpp11/02-range-based-for","permalink":"/LearnModernCpp/docs/cpp11/02-range-based-for","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp11","permalink":"/LearnModernCpp/docs/tags/cpp-11"},{"inline":true,"label":"range_based_for","permalink":"/LearnModernCpp/docs/tags/range-based-for"}],"version":"current","sidebarPosition":3,"frontMatter":{"sidebar_position":3,"slug":"02-range-based-for","title":"\u8303\u56f4for\u5faa\u73af (Range-based for loop)","description":"C++11 \u8303\u56f4for\u5faa\u73af (Range-based for loop) \u6559\u5b66\u793a\u4f8b","tags":["cpp11","range_based_for"]},"sidebar":"docs","previous":{"title":"auto\u7c7b\u578b\u63a8\u5bfc\u4e0edecltype","permalink":"/LearnModernCpp/docs/cpp11/01-auto-and-decltype"},"next":{"title":"Lambda\u8868\u8fbe\u5f0f","permalink":"/LearnModernCpp/docs/cpp11/03-lambda-expressions"}}');var o=t(74848),s=t(28453);const d={sidebar_position:3,slug:"02-range-based-for",title:"\u8303\u56f4for\u5faa\u73af (Range-based for loop)",description:"C++11 \u8303\u56f4for\u5faa\u73af (Range-based for loop) \u6559\u5b66\u793a\u4f8b",tags:["cpp11","range_based_for"]},a="\u8303\u56f4for\u5faa\u73af (Range-based for loop)",c={},i=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function l(r){const n={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,s.R)(),...r.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(n.header,{children:(0,o.jsx)(n.h1,{id:"\u8303\u56f4for\u5faa\u73af-range-based-for-loop",children:"\u8303\u56f4for\u5faa\u73af (Range-based for loop)"})}),"\n",(0,o.jsx)(n.p,{children:"C++11 \u6807\u51c6\u5f15\u5165\u7684 \u8303\u56f4for\u5faa\u73af (Range-based for loop) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,o.jsx)(n.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,o.jsx)(n.pre,{children:(0,o.jsx)(n.code,{className:"language-cpp",metastring:'title="cpp11/02_range_based_for.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: \u8303\u56f4for\u5faa\u73af (Range-based for loop)\r\n * \u6240\u5c5e\u6807\u51c6: C++11\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: \u4e00\u79cd\u7b80\u6d01\u7684\u5faa\u73af\u8bed\u6cd5\uff0c\u7528\u4e8e\u904d\u5386\u5bb9\u5668\u3001\u6570\u7ec4\u6216\u4efb\u4f55\r\n *          \u63d0\u4f9bbegin()/end()\u7684\u5bf9\u8c61\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: C++03\u4e2d\u904d\u5386\u5bb9\u5668\u9700\u8981\u624b\u5199\u8fed\u4ee3\u5668\u6216\u4e0b\u6807\u5faa\u73af\uff0c\r\n *   \u4ee3\u7801\u5197\u957f\u4e14\u5bb9\u6613\u51fa\u9519\u3002\u8303\u56f4for\u5faa\u73af\u8ba9\u904d\u5386\u53d8\u5f97\u7b80\u6d01\u4e14\u4e0d\u6613\u51fa\u9519\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - \u8bed\u6cd5: for (declaration : expression) { ... }\r\n *   - \u7528\u503c\u62f7\u8d1d\u904d\u5386\u3001\u7528\u5f15\u7528\u4fee\u6539\u5143\u7d20\u3001\u7528const\u5f15\u7528\u53ea\u8bfb\u9ad8\u6548\u8bbf\u95ee\r\n *   - \u53ef\u4f5c\u7528\u4e8e\u6570\u7ec4\u3001STL\u5bb9\u5668\u3001initializer_list\r\n *   - \u81ea\u5b9a\u4e49\u7c7b\u578b\u9700\u63d0\u4f9bbegin()\u548cend()\u65b9\u6cd5\u6216\u5bf9\u5e94\u7684\u81ea\u7531\u51fd\u6570\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <vector>\r\n#include <map>\r\n#include <string>\r\n#include <initializer_list>\r\n\r\n// ============================================================\r\n// \u81ea\u5b9a\u4e49\u53ef\u904d\u5386\u7c7b\u578b\uff1a\u7b80\u5355\u7684\u6574\u6570\u8303\u56f4 [start, end)\r\n// ============================================================\r\nclass IntRange {\r\npublic:\r\n    // \u8fed\u4ee3\u5668\u7c7b\uff08\u6700\u7b80\u5355\u7684\u524d\u5411\u8fed\u4ee3\u5668\uff09\r\n    class Iterator {\r\n    public:\r\n        explicit Iterator(int val) : value_(val) {}\r\n        int operator*() const { return value_; }\r\n        Iterator& operator++() { ++value_; return *this; }\r\n        bool operator!=(const Iterator& other) const { return value_ != other.value_; }\r\n    private:\r\n        int value_;\r\n    };\r\n\r\n    IntRange(int start, int end) : start_(start), end_(end) {}\r\n\r\n    Iterator begin() const { return Iterator(start_); }\r\n    Iterator end() const { return Iterator(end_); }\r\n\r\nprivate:\r\n    int start_;\r\n    int end_;\r\n};\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\nvoid basic_usage() {\r\n    std::cout << "===== \u57fa\u7840\u7528\u6cd5 =====" << std::endl;\r\n\r\n    // 1. \u904d\u5386STL\u5bb9\u5668\r\n    std::vector<std::string> fruits = {"\u82f9\u679c", "\u9999\u8549", "\u6a58\u5b50", "\u8461\u8404"};\r\n    std::cout << "\u6c34\u679c\u5217\u8868: ";\r\n    for (const auto& fruit : fruits) {\r\n        std::cout << fruit << " ";\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 2. \u904d\u5386C\u98ce\u683c\u6570\u7ec4\r\n    int scores[] = {90, 85, 78, 92, 88};\r\n    std::cout << "\u6210\u7ee9: ";\r\n    for (auto score : scores) {\r\n        std::cout << score << " ";\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 3. \u904d\u5386\u521d\u59cb\u5316\u5217\u8868\uff08\u4e34\u65f6\u7684initializer_list\uff09\r\n    std::cout << "\u76f4\u63a5\u904d\u5386\u5b57\u9762\u91cf: ";\r\n    for (auto x : {10, 20, 30, 40}) {\r\n        std::cout << x << " ";\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 4. \u904d\u5386std::map\uff08\u7ed3\u6784\u5316\u7ed1\u5b9a\u662fC++17\uff0cC++11\u7528pair\uff09\r\n    std::map<std::string, int> ages = {{"\u5f20\u4e09", 25}, {"\u674e\u56db", 30}, {"\u738b\u4e94", 28}};\r\n    std::cout << "\u5e74\u9f84\u8868:" << std::endl;\r\n    for (const auto& pair : ages) {\r\n        std::cout << "  " << pair.first << ": " << pair.second << "\u5c81" << std::endl;\r\n    }\r\n\r\n    // 5. \u904d\u5386\u5b57\u7b26\u4e32\u4e2d\u7684\u5b57\u7b26\r\n    std::string text = "Hello";\r\n    std::cout << "\u5b57\u7b26: ";\r\n    for (char c : text) {\r\n        std::cout << c << \' \';\r\n    }\r\n    std::cout << std::endl;\r\n}\r\n\r\n// ============================================================\r\n// \u8fdb\u9636\u7528\u6cd5\r\n// ============================================================\r\nvoid advanced_usage() {\r\n    std::cout << "\\n===== \u8fdb\u9636\u7528\u6cd5 =====" << std::endl;\r\n\r\n    // 1. \u7528\u5f15\u7528\u4fee\u6539\u5bb9\u5668\u5143\u7d20\r\n    std::vector<int> numbers = {1, 2, 3, 4, 5};\r\n    std::cout << "\u4fee\u6539\u524d: ";\r\n    for (auto n : numbers) std::cout << n << " ";\r\n    std::cout << std::endl;\r\n\r\n    for (auto& n : numbers) {\r\n        n *= 2; // \u901a\u8fc7\u5f15\u7528\u76f4\u63a5\u4fee\u6539\u539f\u59cb\u5143\u7d20\r\n    }\r\n\r\n    std::cout << "\u4fee\u6539\u540e(\u5168\u90e8\u7ffb\u500d): ";\r\n    for (const auto& n : numbers) std::cout << n << " ";\r\n    std::cout << std::endl;\r\n\r\n    // 2. \u4f7f\u7528\u81ea\u5b9a\u4e49\u7684IntRange\u7c7b\r\n    std::cout << "IntRange(1, 10): ";\r\n    for (auto i : IntRange(1, 10)) {\r\n        std::cout << i << " ";\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 3. \u5d4c\u5957\u8303\u56f4for\u5faa\u73af\r\n    std::vector<std::vector<int>> matrix = {\r\n        {1, 2, 3},\r\n        {4, 5, 6},\r\n        {7, 8, 9}\r\n    };\r\n    std::cout << "\u77e9\u9635:" << std::endl;\r\n    for (const auto& row : matrix) {\r\n        std::cout << "  ";\r\n        for (auto val : row) {\r\n            std::cout << val << " ";\r\n        }\r\n        std::cout << std::endl;\r\n    }\r\n\r\n    // 4. \u4f7f\u7528auto&&\uff08\u4e07\u80fd\u5f15\u7528\uff09\u2014\u2014 \u80fd\u7ed1\u5b9a\u5de6\u503c\u548c\u53f3\u503c\r\n    std::vector<std::string> words = {"\u4f60\u597d", "\u4e16\u754c"};\r\n    for (auto&& word : words) {\r\n        std::cout << word << " ";\r\n    }\r\n    std::cout << std::endl;\r\n}\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9\u4e0e\u9677\u9631\r\n// ============================================================\r\nvoid pitfalls() {\r\n    std::cout << "\\n===== \u6613\u9519\u70b9\u4e0e\u9677\u9631 =====" << std::endl;\r\n\r\n    // \u9677\u96311: \u5728\u8303\u56f4for\u5faa\u73af\u4e2d\u4fee\u6539\u5bb9\u5668\u5927\u5c0f\uff08\u6dfb\u52a0/\u5220\u9664\u5143\u7d20\uff09\r\n    // \u8fd9\u4f1a\u5bfc\u81f4\u672a\u5b9a\u4e49\u884c\u4e3a\uff0c\u56e0\u4e3a\u8fed\u4ee3\u5668\u4f1a\u5931\u6548\uff01\r\n    std::vector<int> vec = {1, 2, 3, 4, 5};\r\n    // \u9519\u8bef\u793a\u4f8b\uff08\u4e0d\u8981\u8fd9\u6837\u505a\uff01\uff09\uff1a\r\n    // for (auto& v : vec) {\r\n    //     if (v == 3) vec.push_back(99); // \u672a\u5b9a\u4e49\u884c\u4e3a!\r\n    // }\r\n    std::cout << "\u8b66\u544a: \u8303\u56f4for\u5faa\u73af\u4e2d\u4e0d\u80fd\u6dfb\u52a0/\u5220\u9664\u5bb9\u5668\u5143\u7d20!" << std::endl;\r\n\r\n    // \u9677\u96312: \u5bf9\u5927\u578b\u5bf9\u8c61\u7528\u503c\u62f7\u8d1d\u904d\u5386\uff08\u6027\u80fd\u95ee\u9898\uff09\r\n    std::vector<std::string> big_strings = {"\u5f88\u957f\u5f88\u957f\u7684\u5b57\u7b26\u4e32\u4e00", "\u5f88\u957f\u5f88\u957f\u7684\u5b57\u7b26\u4e32\u4e8c"};\r\n    // \u4e0d\u597d \u2014\u2014 \u6bcf\u6b21\u8fed\u4ee3\u90fd\u62f7\u8d1d\u4e00\u4e2astring\r\n    // for (auto s : big_strings) { ... }\r\n    // \u597d \u2014\u2014 \u7528const\u5f15\u7528\u907f\u514d\u62f7\u8d1d\r\n    for (const auto& s : big_strings) {\r\n        std::cout << s << std::endl;\r\n    }\r\n\r\n    // \u9677\u96313: \u8303\u56f4for\u4e0d\u63d0\u4f9b\u7d22\u5f15\r\n    // \u5982\u679c\u4f60\u9700\u8981\u7d22\u5f15\uff0c\u5e94\u8be5\u7528\u4f20\u7edffor\u5faa\u73af\u6216\u624b\u52a8\u7ef4\u62a4\u8ba1\u6570\u5668\r\n    std::vector<std::string> items = {"\u7532", "\u4e59", "\u4e19"};\r\n    int index = 0;\r\n    for (const auto& item : items) {\r\n        std::cout << "  \u7d22\u5f15 " << index++ << ": " << item << std::endl;\r\n    }\r\n\r\n    // \u9677\u96314: \u4e0d\u80fd\u76f4\u63a5\u7528\u4e8e\u52a8\u6001\u6570\u7ec4\uff08\u6307\u9488\uff09\r\n    // int* arr = new int[5]{1,2,3,4,5};\r\n    // for (auto x : arr) {} // \u7f16\u8bd1\u9519\u8bef! \u6307\u9488\u6ca1\u6709begin/end\r\n    // delete[] arr;\r\n    std::cout << "\u6ce8\u610f: \u52a8\u6001\u6570\u7ec4(\u6307\u9488)\u4e0d\u80fd\u7528\u8303\u56f4for\u904d\u5386" << std::endl;\r\n}\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "========================================" << std::endl;\r\n    std::cout << "  C++11 \u7279\u6027: \u8303\u56f4for\u5faa\u73af" << std::endl;\r\n    std::cout << "========================================" << std::endl;\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,o.jsx)(n.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,o.jsxs)(n.ul,{children:["\n",(0,o.jsx)(n.li,{children:(0,o.jsx)(n.a,{href:"https://en.cppreference.com/w/cpp/language/range-for",children:"cppreference: \u8303\u56f4for\u5faa\u73af (Range-based for loop)"})}),"\n"]})]})}function u(r={}){const{wrapper:n}={...(0,s.R)(),...r.components};return n?(0,o.jsx)(n,{...r,children:(0,o.jsx)(l,{...r})}):l(r)}},28453(r,n,t){t.d(n,{R:()=>d,x:()=>a});var e=t(96540);const o={},s=e.createContext(o);function d(r){const n=e.useContext(s);return e.useMemo(function(){return"function"==typeof r?r(n):{...n,...r}},[n,r])}function a(r){let n;return n=r.disableParentContext?"function"==typeof r.components?r.components(o):r.components||o:d(r.components),e.createElement(s.Provider,{value:n},r.children)}}}]);